mapper.select:
select u.nickname,u.avatar,u.id as userId,u.introduction,f.created_at as createdAt
from follow f
left join user u on u.id = f.following_id
where f.following_id = #{followerId}
order by f.created_at desc
limit #{pageSize} offset #{offset}

select u.nickname,u.avatar,u.id as userId,u.introduction,f.created_at as createdAt
from follow f
       left join user u on u.id = f.follower_id
where f.following_id = #{followingId}
order by f.created_at desc
  limit #{pageSize} offset #{offset}
